/**
 * One block in the runner's Phase Planner config. The trailing 16-week
Marathon-Specific block is auto-pinned at generation time and is NOT
present in the user-defined `blocks` array; users only pick the
blocks that come BEFORE the auto-pinned tail.

 */
export interface PhaseBlock {
  focusType: PhaseBlockFocusType;
  /** @minimum 1 */
  weeks: number;
  /** Required when focusType is "Custom"; ignored otherwise. Used as the phase label on plan_weeks/plan_days for that block. */
  customName?: string | null;
  /** Optional free-text appended in `[brackets]` to every plan_day description in this block (handy for marking experiments, "extra recovery", etc.). */
  customNotes?: string | null;
}

/**
 * A single composed entry inside an entries-mode PlannerConfig. References a plan template by id and supplies the runner-chosen week count for that template.
 */
export interface TemplateEntry {
  /** Identifier of an entry in PLAN_TEMPLATES (e.g. "half_marathon", "marathon", "aerobic_base"). Unknown ids are rejected at validation. */
  templateId: string;
  /**
   * Number of weeks this entry's template should expand to. Must be a positive integer within the referenced template's published min/max range — out-of-range values are rejected at validation.
   * @minimum 1
   */
  weeks: number;
  /** Optional runner-friendly label for this composition entry; merged into the first expanded block's customName. */
  customName?: string | null;
  /** Optional per-entry note merged into every expanded block's customNotes so the runner-supplied context surfaces in the daily plan. */
  customNotes?: string | null;
  /** Optional ISO yyyy-mm-dd Monday on which this entry begins. When omitted (null), the entry stacks immediately after the previous entry. When set later than the running cursor, the gap is bridged with a Recovery filler block (sum of entry weeks + gap weeks must still equal totalWeeks). The first entry's startDate, when set, must equal the config's startDate. Overlapping entries (startDate before the previous entry's end) are rejected at validation. */
  startDate?: string | null;
}

export interface PlannerConfig {
  /** Server-assigned identifier. Stable across renames. */
  id: number;
  /** Human-friendly label shown in the config dropdown. */
  name: string;
  /** True if this is the config that POST /planner/apply will operate on. */
  isActive: boolean;
  /** ISO yyyy-mm-dd; week 1 begins on this date. Must be a Monday. */
  startDate: string;
  /** ISO yyyy-mm-dd; race / final day. Must be a Sunday. In legacy blocks-mode it must be at least 16 weeks after startDate (the auto-pinned Marathon-Specific tail). In entries-mode it must equal sum(entries.weeks) weeks after startDate (templates own their own taper). */
  marathonDate: string;
  /** In legacy mode, the user-edited PhaseBlock list (auto-pinned 16-week tail appended at generation time). In entries-mode, the server-computed projection of `entries` for downstream consumers. */
  blocks: PhaseBlock[];
  /** Ordered list of TemplateEntry objects. When non-null, entries are the source of truth for the editor; the server projects entries → blocks on every write. Sum of entry weeks must equal totalWeeks (no auto-pinned tail). NULL for legacy blocks-only configs. */
  entries?: TemplateEntry[] | null;
  notes?: string | null;
  /** Server-set timestamp for the most recent write. Read-only — ignored on writes. */
  updatedAt?: string;
  /** Timestamp of the most recent /planner/apply that pivoted on this config. NULL if it has never been applied. */
  lastAppliedAt?: string | null;
}

